mapper.update:
		UPDATE ${schema}.WSTKKY
		   SET OWNRNAM = #{param.ownrnam}
             , FNCUSKY = #{param.fncusky}
             , BTRCATE = #{param.btrcate}
             , STKMEMO = CONCAT(STKMEMO, ' // [전환]')
             , REGIMOD = #{param.regikey}

             	, DEORGNM = #{param.deorgnm}

             , DEMODNM = #{param.demodnm}
             , DEMODYN = #{param.demodyn}
             , LMODATE = TO_CHAR(current_timestamp(),'YYYYMMDD')
             , LMOTIME = TO_CHAR(current_timestamp(),'HH24MISS')
             , LMOUSER = 'SYS'
             , UPDTCHK = UPDTCHK + 1
         WHERE SKUMKEY = #{param.skumkey}
           AND UPDTCHK = (
           					SELECT UPDTCHK
           					  FROM ${schema}.WSTKKY
           					 WHERE SKUMKEY = #{param.skumkey}
           )

UPDATE ${schema}.IFKSURE
   SET IFPRSTS = #{param.ifprsts}

     	, IFERRNM = #{param.iferrnm}

 WHERE SKUMKEY = #{param.skumkey}
   AND IFPRSTS = 'U'

