/* updateWasnhdStat */ UPDATE ${apiCommon.schema}.WASNHD SET ASNSTAT = #{data.asnstat},
RSNCODE = #{data.rsncode},
LMODATE = date_format(now(), '%Y%m%d'), LMOTIME = date_format(now(), '%H%i%s'), LMOUSER = #{apiCommon.useract}, UPDTCHK = UPDTCHK + 1 WHERE EOASNKY = #{data.eoasnky}

mapper.select:
/* checkInboundStart */
SELECT
    COUNT(1)
FROM
    ${apiCommon.schema}.WTAKIT WT
INNER JOIN ${apiCommon.schema}.WASNIT WA
    ON WA.EOASNKY = WT.EOASNKY
    AND WA.EOASNIT = WT.EOASNIT
WHERE
    WT.EOASNKY = #{param.eoasnky}
    AND WT.TASKOKY = #{param.taskoky}

    	AND WT.TASKSTS = #{param.tasksts}

