	SET AREAKEY = #{data.toareky},
		LOCAKEY = #{data.tolocky},
		LOLAYER = #{data.tolayer},
		LMODATE = date_format(now(), '%Y%m%d'),
		LMOTIME = date_format(now(), '%H%i%s'),
		LMOUSER = #{apiCommon.useract}
	WHERE
		SKUMKEY = #{data.skumkey}
